1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.StatusOr;
6	import com.fortinet.nac.ingestion.client.PolicyNotificationClient;
7	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
8	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
9	import com.fortinet.nac.ingestion.entity.Entity;
10	import com.fortinet.nac.common.enums.EntityStage;
11	import com.fortinet.nac.ingestion.service.EntityService;
12	
13	import lombok.RequiredArgsConstructor;
14	import lombok.extern.slf4j.Slf4j;
15	import org.springframework.stereotype.Component;
16	
17	@Slf4j
18	@Component
19	@RequiredArgsConstructor
20	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
21	
22	    private final EntityService entityService;
23	    private final EntityStateMachine stateMachine;
24	    private final PolicyNotificationClient policyNotificationClient;
25	
26	    @Override
27	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
28	
29	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
30	                e.getId());
31	
32	        e.setAttributeFingerprint(reqFp);
33	        e.setProcessingStage(EntityStage.PENDING.toString());
34	        e.setProcessingCode(0);
35	        e.setInterrupted(false);
36	        e.setLastReqVersion(req.getVersion());
37	        e.setProcessingResult("{}");
38	        e.setErrorMessage("");
39	
40	        boolean ok = entityService.updateProcessingState(e);
41	        if (!ok) {
42	            log.error("Failed to reset processing state, entityId={}", e.getId());
43	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
44	                    "failed to reset processing state");
45	        }
46	
47	        policyNotificationClient.notifyEntityReset(e.getId());
48	
49	        return stateMachine.start(req.getRequestId(), req.isAsync(), e);
50	    }
51	}
