1	package com.fortinet.nac.ingestion.controller;
2	
3	import com.fortinet.nac.common.dto.ResultDTO;
4	import com.fortinet.nac.ingestion.dto.MarkForReprocessResponse;
5	import com.fortinet.nac.ingestion.dto.MarkForReprocessResult;
6	import com.fortinet.nac.ingestion.job.event.PolicyReprocessRequestedEvent;
7	import com.fortinet.nac.ingestion.service.EntityService;
8	import lombok.RequiredArgsConstructor;
9	import lombok.extern.slf4j.Slf4j;
10	import org.springframework.context.ApplicationEventPublisher;
11	import org.springframework.web.bind.annotation.PostMapping;
12	import org.springframework.web.bind.annotation.RequestMapping;
13	import org.springframework.web.bind.annotation.RestController;
14	
15	@RestController
16	@RequestMapping("/api/v1/policy")
17	@RequiredArgsConstructor
18	@Slf4j
19	public class PolicyController {
20	
21	    private final EntityService entityService;
22	    private final ApplicationEventPublisher eventPublisher;
23	
24	    @PostMapping("/apply-existing-entities")
25	    public ResultDTO<MarkForReprocessResponse> applyExistingEntities() {
26	        log.info("PolicyController: received request to apply policy to all existing entities");
27	        long startNanos = System.nanoTime();
28	
29	        try {
30	            // Mark all entities' reprocessState as INIT.
31	            MarkForReprocessResult markResult = entityService.markAllForReprocess();
32	
33	            int count = markResult.getUpdatedCount();
34	            int failedCount = markResult.getFailedCount();
35	            if (count > 0) {
36	                // Trigger an immediate scan, while the scheduled job remains as fallback.
37	                eventPublisher.publishEvent(new PolicyReprocessRequestedEvent(count, "api"));
38	            }
39	
40	            String status;
41	            String message;
42	            if (failedCount > 0 && count == 0) {
43	                status = "FAILED";
44	                message = String.format("Failed to mark entities, failedCount=%d", failedCount);
45	                log.warn("PolicyController: mark entities failed, markedCount=0, failedCount={}, failedBatches={}",
46	                        failedCount, markResult.getFailedBatches());
47	            } else if (failedCount > 0) {
48	                status = "PARTIAL_SUCCESS";
49	                message = String.format("Marked %d entities; %d entities failed during marking", count, failedCount);
50	                log.warn("PolicyController: marked entities with partial failures, markedCount={}, failedCount={}, failedBatches={}",
51	                        count, failedCount, markResult.getFailedBatches());
52	            } else {
53	                status = "SUCCESS";
54	                message = String.format("Marked %d entities for reprocessing", count);
55	                log.info("PolicyController: successfully marked {} entities for reprocessing", count);
56	            }
57	
58	            return ResultDTO.success(
59	                    MarkForReprocessResponse.builder()
60	                            .markedCount(count)
61	                            .failedBatches(markResult.getFailedBatches())
62	                            .failedCount(failedCount)
63	                            .timeCostMs((System.nanoTime() - startNanos) / 1_000_000)
64	                            .status(status)
65	                            .message(message)
66	                            .build());
67	        } catch (Exception e) {
68	            log.error("PolicyController: failed to mark entities for reprocessing", e);
69	
70	            return ResultDTO.<MarkForReprocessResponse>builder()
71	                    .code(ResultDTO.DEFAULT_ERROR_CODE)
72	                    .errMsg("Failed with err=" + e.getMessage())
73	                    .data(MarkForReprocessResponse.builder()
74	                            .markedCount(0)
75	                            .failedBatches(0)
76	                            .failedCount(0)
77	                            .timeCostMs((System.nanoTime() - startNanos) / 1_000_000)
78	                            .status("FAILED")
79	                            .message("Failed to mark entities for reprocessing")
80	                            .build())
81	                    .build();
82	        }
83	    }
84	}
