1	package com.fortinet.nac.ingestion.job;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.enums.EntityStage;
5	import com.fortinet.nac.common.enums.ReprocessState;
6	import com.fortinet.nac.common.redis.DistributedLock;
7	import com.fortinet.nac.common.util.StatusOr;
8	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
9	import com.fortinet.nac.ingestion.entity.Entity;
10	import com.fortinet.nac.ingestion.job.event.PolicyReprocessRequestedEvent;
11	import com.fortinet.nac.ingestion.repository.projection.EntityProcessLockInfo;
12	import com.fortinet.nac.ingestion.service.EntityService;
13	import com.fortinet.nac.ingestion.util.RedisUtil;
14	import io.micrometer.core.instrument.Counter;
15	import io.micrometer.core.instrument.MeterRegistry;
16	import io.micrometer.core.instrument.Timer;
17	import lombok.RequiredArgsConstructor;
18	import lombok.extern.slf4j.Slf4j;
19	import org.springframework.beans.factory.annotation.Value;
20	import org.springframework.context.event.EventListener;
21	import org.springframework.scheduling.annotation.Async;
22	import org.springframework.scheduling.annotation.Scheduled;
23	import org.springframework.stereotype.Component;
24	
25	import javax.annotation.PostConstruct;
26	import javax.annotation.Resource;
27	import java.util.ArrayList;
28	import java.util.List;
29	import java.util.UUID;
30	import java.util.concurrent.CompletableFuture;
31	import java.util.concurrent.Executor;
32	import java.util.concurrent.TimeUnit;
33	import java.util.concurrent.atomic.AtomicInteger;
34	
35	@Component
36	@RequiredArgsConstructor
37	@Slf4j
38	public class PolicyReprocessJob {
39	
40	    private final EntityService entityService;
41	    private final DistributedLock distributedLock;
42	    private final EntityStateMachine stateMachine;
43	    private final MeterRegistry meterRegistry;
44	    private final AtomicInteger scanLockConsecutiveFailures = new AtomicInteger(0);
45	    @Resource(name = "policyReprocessJobExecutor")
46	    private Executor policyReprocessJobExecutor;
47	
48	    @Value("${policy.reprocess.scan-batch-size:${policy.reprocess.batch-size:100}}")
49	    private int scanBatchSize;
50	
51	    @Value("${policy.reprocess.max-candidates-per-scan:${policy.reprocess.max-entities-per-scan:1000}}")
52	    private int maxCandidatesPerScan;
53	
54	    @Value("${policy.reprocess.rate-limit-per-second:100}")
55	    private int rateLimitPerSecond;
56	
57	    @Value("${policy.reprocess.scan-lock-ttl-seconds:900}")
58	    private int scanLockTtlSeconds;
59	
60	    @PostConstruct
61	    public void initMetrics() {
62	        // Gauge for starvation visibility: how many scan-lock failures occurred continuously.
63	        meterRegistry.gauge("policy_reprocess_scan_lock_consecutive_failures", scanLockConsecutiveFailures);
64	    }
65	
66	    @Scheduled(fixedDelayString = "${policy.reprocess.scan-interval-ms:30000}")
67	    public void scanAndReprocessInitEntities() {
68	        triggerScan("scheduled");
69	    }
70	
71	    @Async("policyReprocessListenerExecutor")
72	    @EventListener
73	    public void onPolicyReprocessRequested(PolicyReprocessRequestedEvent event) {
74	        log.info("PolicyReprocessJob: receive reprocess trigger from {}, markedCount={}",
75	                event.getTriggerSource(), event.getMarkedCount());
76	        triggerScan("event");
77	    }
78	
79	    private void triggerScan(String triggerSource) {
80	        // PolicyReprocessJob currently runs on a single node, so distributed contention is limited.
81	        // Keep the distributed scan lock for future cluster deployments to prevent concurrent full scans.
82	        // Global scan lock uses fixed TTL to avoid indefinite lock extension when scan thread is stuck.
83	        boolean acquired = distributedLock.tryLock(
84	                Constants.RedisKeys.POLICY_REPROCESS_SCAN_LOCK_KEY,
85	                Math.max(1, scanLockTtlSeconds));
86	        recordLockAcquire("scan", acquired);
87	        if (!acquired) {
88	            scanLockConsecutiveFailures.incrementAndGet();
89	            log.warn("PolicyReprocessJob: skip {} trigger because global scan lock is held", triggerSource);
90	            return;
91	        }
92	        scanLockConsecutiveFailures.set(0);
93	
94	        Timer.Sample lockHoldSample = Timer.start(meterRegistry);
95	
96	        try {
97	            drainInitEntities();
98	        } finally {
99	            distributedLock.unLock(Constants.RedisKeys.POLICY_REPROCESS_SCAN_LOCK_KEY);
100	            lockHoldSample.stop(lockHoldTimer("scan"));
101	        }
102	    }
103	
104	    private void drainInitEntities() {
105	        int effectiveBatchSize = Math.max(1, scanBatchSize);
106	        int effectiveMaxCandidatesPerScan = Math.max(1, maxCandidatesPerScan);
107	
108	        ReprocessRateLimiter rateLimiter = new ReprocessRateLimiter(rateLimitPerSecond, meterRegistry);
109	
110	        int totalScannedCandidates = 0;
111	        while (totalScannedCandidates < effectiveMaxCandidatesPerScan) {
112	
113	            // Respect scan-level protection limit to avoid too much one-shot pressure.
114	            int queryLimit = Math.min(effectiveBatchSize, effectiveMaxCandidatesPerScan - totalScannedCandidates);
115	
116	            // Query only ids first to avoid fetching large columns such as processingResult.
117	            List<Long> batchIds = entityService.findTopNIdsByReprocessState(
118	                    ReprocessState.INIT, queryLimit);
119	            if (batchIds.isEmpty()) {
120	                break;
121	            }
122	            totalScannedCandidates += batchIds.size();
123	
124	            processBatchConcurrently(batchIds, rateLimiter);
125	            log.info("PolicyReprocessJob: batch processed, size={}", batchIds.size());
126	
127	            // If we got fewer than one full batch, queue is likely drained for this run.
128	            if (batchIds.size() < queryLimit) {
129	                break;
130	            }
131	        }
132	    }
133	
134	    private void processBatchConcurrently(List<Long> batchIds, ReprocessRateLimiter rateLimiter) {
135	        List<CompletableFuture<Void>> futures = new ArrayList<>(batchIds.size());
136	        for (Long entityId : batchIds) {
137	            futures.add(CompletableFuture.runAsync(
138	                    () -> reprocessOneEntitySafely(entityId, rateLimiter),
139	                    policyReprocessJobExecutor
140	            ));
141	        }
142	
143	        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();
144	    }
145	
146	    private void reprocessOneEntitySafely(Long entityId, ReprocessRateLimiter rateLimiter) {
147	        try {
148	            reprocessOneEntity(entityId, rateLimiter);
149	        } catch (Exception ex) {
150	            log.error("PolicyReprocessJob: reprocess entity {} failed, err={}",
151	                    entityId, ex.toString(), ex);
152	        }
153	    }
154	
155	    private void reprocessOneEntity(Long entityId, ReprocessRateLimiter rateLimiter) {
156	        // First read only lock-related fields to avoid loading large columns too early.
157	        EntityProcessLockInfo lockInfo = entityService.findProcessLockInfoById(entityId);
158	        if (lockInfo == null) {
159	            log.warn("PolicyReprocessJob: entity {} not found", entityId);
160	            return;
161	        }
162	
163	        if (lockInfo.getReprocessState() != ReprocessState.INIT) {
164	            // State already changed by another flow, skip.
165	            return;
166	        }
167	
168	        // 1) Acquire processLock first to avoid conflict with normal ingestion flow.
169	        String processLockKey = RedisUtil.getEntityProcessLockKey(
170	                lockInfo.getType(), lockInfo.getHostId(), lockInfo.getAdapterId(), lockInfo.getUserId());
171	        boolean locked = distributedLock.tryLock(
172	                processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
173	        recordLockAcquire("entity", locked);
174	
175	        if (!locked) {
176	            // The entity is being handled by other flow; retry next round.
177	            log.info("PolicyReprocessJob: skip entity {} because processLock is held", entityId);
178	            return;
179	        }
180	
181	        Timer.Sample lockHoldSample = Timer.start(meterRegistry);
182	        try {
183	            // Atomic claim in DB: only one worker can move INIT -> RUNNING.
184	            // claimInitEntityForReprocess is essentially a claim operation for processing ownership:
185	            //   it turns "check INIT then set RUNNING" into one atomic step to remove race windows.
186	            boolean claimed = entityService.claimInitEntityForReprocess(entityId);
187	            if (!claimed) {
188	                return;
189	            }
190	
191	            // Load full entity only after claim succeeds.
192	            Entity fresh = entityService.getEntity(entityId);
193	            if (fresh == null) {
194	                log.warn("PolicyReprocessJob: entity {} missing after claim", entityId);
195	                return;
196	            }
197	
198	            // 2) Reset business processing state so state machine can replay.
199	            resetEntityProcessingState(fresh);
200	            boolean ok = entityService.updateProcessingState(fresh);
201	            if (!ok) {
202	                log.error("PolicyReprocessJob: failed to reset processing state, entityId={}", entityId);
203	                boolean updated = entityService.updateReprocessStateById(entityId, ReprocessState.FAILED);
204	                if (!updated) {
205	                    log.warn("PolicyReprocessJob: failed to update FAILED reprocess state, entityId={}", entityId);
206	                }
207	                recordReprocessCompletion("failed");
208	                return;
209	            }
210	
211	            // 3) Run state machine with rate limiting to protect downstream.
212	            rateLimiter.acquire();
213	            String requestId = generateRequestId();
214	            StatusOr<Entity> result = stateMachine.start(requestId, true, fresh);
215	
216	            // 4) Update final reprocessState by state machine result.
217	            if (result.ok()) {
218	                Entity finalEntity = result.getValue();
219	                if (EntityStage.ENFORCED.toString().equals(finalEntity.getProcessingStage()) &&
220	                        finalEntity.getProcessingCode() == 0) {
221	                    finalEntity.setReprocessState(ReprocessState.SUCCESS);
222	                } else {
223	                    finalEntity.setReprocessState(ReprocessState.FAILED);
224	                }
225	
226	                // Persist the state-machine final snapshot to avoid overriding it with stale "fresh".
227	                entityService.save(finalEntity);
228	                if (finalEntity.getReprocessState() == ReprocessState.SUCCESS) {
229	                    recordReprocessCompletion("success");
230	                } else {
231	                    recordReprocessCompletion("failed");
232	                }
233	            } else {
234	                // State-machine returned error; update FAILED by id to avoid another full-row read.
235	                boolean updated = entityService.updateReprocessStateById(entityId, ReprocessState.FAILED);
236	                if (!updated) {
237	                    log.warn("PolicyReprocessJob: failed to update FAILED state after state machine error, entityId={}", entityId);
238	                }
239	                recordReprocessCompletion("failed");
240	            }
241	
242	        } finally {
243	            distributedLock.unLock(processLockKey);
244	            lockHoldSample.stop(lockHoldTimer("entity"));
245	        }
246	    }
247	
248	    // update in memory
249	    private void resetEntityProcessingState(Entity e) {
250	        e.setInterrupted(false);
251	        e.setProcessingStage(EntityStage.PENDING.toString());
252	        e.setProcessingCode(0);
253	        e.setProcessingResult("{}");
254	        e.setErrorMessage("");
255	        // Keep lastReqVersion unchanged.
256	    }
257	
258	    private String generateRequestId() {
259	        return UUID.randomUUID().toString().replace("-", "").substring(0, 16);
260	    }
261	
262	    private void recordLockAcquire(String lockName, boolean success) {
263	        meterRegistry.counter(
264	                "policy_reproc_lock_acquire_total",
265	                "lock", lockName,
266	                "result", success ? "success" : "failed"
267	        ).increment();
268	    }
269	
270	    private void recordReprocessCompletion(String result) {
271	        meterRegistry.counter(
272	                "policy_reprocess_entity_completed_total",
273	                "result", result
274	        ).increment();
275	    }
276	
277	    private Timer lockHoldTimer(String lockName) {
278	        return Timer.builder("policy_reproc_lock_hold_seconds")
279	                .tag("lock", lockName)
280	                .register(meterRegistry);
281	    }
282	
283	    // ReprocessRateLimiter is a per-second limiter used to protect downstream systems.
284	    // It prevents PolicyReprocessJob from reprocessing too many entities in a short time.
285	    private static final class ReprocessRateLimiter {
286	        private static final long ONE_SECOND_NANOS = TimeUnit.SECONDS.toNanos(1);
287	
288	        // Token bucket refill rate: number of tokens added per second.
289	        private final int refillTokensPerSecond;
290	        // Bucket capacity: allows short bursts while keeping an upper bound.
291	        private final double capacity;
292	        // Count how many acquire() calls were throttled (had to wait).
293	        private final Counter waitCounter;
294	
295	        private double availableTokens;
296	        private long lastRefillNanos = System.nanoTime();
297	
298	        private ReprocessRateLimiter(int maxPerSecond, MeterRegistry meterRegistry) {
299	            this.refillTokensPerSecond = Math.max(0, maxPerSecond);
300	            this.capacity = this.refillTokensPerSecond <= 0 ? 0.0 : this.refillTokensPerSecond;
301	            this.availableTokens = this.capacity;
302	            this.waitCounter = meterRegistry.counter("policy_reprocess_rate_limiter_wait_total");
303	        }
304	
305	        // Call acquire() before each processing attempt, right before stateMachine.start(...).
306	        private synchronized void acquire() {
307	            if (refillTokensPerSecond <= 0) {
308	                return;
309	            }
310	
311	            refillTokens();
312	
313	            if (availableTokens < 1.0) {
314	                long waitNanos = nanosUntilNextToken();
315	                if (waitNanos > 0) {
316	                    waitCounter.increment();
317	                    try {
318	                        TimeUnit.NANOSECONDS.sleep(waitNanos);
319	                    } catch (InterruptedException ex) {
320	                        Thread.currentThread().interrupt();
321	                        return;
322	                    }
323	                }
324	                refillTokens();
325	            }
326	
327	            // If availableTokens >= 1, consume one token and proceed immediately.
328	            if (availableTokens >= 1.0) {
329	                availableTokens -= 1.0;
330	            } else {
331	                // Floating-point safety fallback.
332	                availableTokens = 0.0;
333	            }
334	        }
335	
336	        // Refill tokens based on elapsed time.
337	        private void refillTokens() {
338	            long now = System.nanoTime();
339	            long elapsedNanos = now - lastRefillNanos;
340	            if (elapsedNanos <= 0) {
341	                return;
342	            }
343	
344	            // Cap refill amount so available tokens never exceed capacity.
345	            double tokensToAdd = (elapsedNanos / (double) ONE_SECOND_NANOS) * refillTokensPerSecond;
346	            if (tokensToAdd <= 0.0) {
347	                return;
348	            }
349	
350	            availableTokens = Math.min(capacity, availableTokens + tokensToAdd);
351	            lastRefillNanos = now;
352	        }
353	
354	        // Sleep until at least one token is available.
355	        private long nanosUntilNextToken() {
356	            double missingTokens = 1.0 - availableTokens;
357	            if (missingTokens <= 0.0 || refillTokensPerSecond <= 0) {
358	                return 0L;
359	            }
360	
361	            return (long) Math.ceil((missingTokens / refillTokensPerSecond) * ONE_SECOND_NANOS);
362	        }
363	    }
364	}
