1	package com.fortinet.nac.ingestion.config;
2	
3	import io.netty.channel.ChannelOption;
4	import org.springframework.beans.factory.annotation.Value;
5	import org.springframework.context.annotation.Bean;
6	import org.springframework.context.annotation.Configuration;
7	import org.springframework.http.client.reactive.ReactorClientHttpConnector;
8	import org.springframework.web.reactive.function.client.WebClient;
9	import reactor.netty.http.client.HttpClient;
10	
11	import java.time.Duration;
12	
13	@Configuration
14	public class PolicyNotificationConfig {
15	
16	    @Value("${policy.service.connect-timeout-ms:100}")
17	    private int connectTimeoutMs;
18	
19	    @Value("${policy.service.read-timeout-ms:200}")
