14	    @Value("${policy.reprocess.listener.core-size:1}")
15	    private int listenerCoreSize;
16	
17	    @Value("${policy.reprocess.listener.max-size:2}")
18	    private int listenerMaxSize;
19	
20	    @Value("${policy.reprocess.listener.queue-capacity:100}")
21	    private int listenerQueueCapacity;
22	
23	    @Value("${policy.reprocess.listener.keep-alive-seconds:60}")
