26	    @Value("${policy.reprocess.job.core-size:8}")
27	    private int jobCoreSize;
28	
29	    @Value("${policy.reprocess.job.max-size:16}")
30	    private int jobMaxSize;
31	
32	    @Value("${policy.reprocess.job.queue-capacity:32}")
