38	    @Bean("policyReprocessListenerExecutor")
39	    public Executor policyReprocessListenerExecutor() {
40	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
41	        executor.setCorePoolSize(listenerCoreSize);
