package com.fortinet.nac.ingestion.job;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.enums.EntityStage;
import com.fortinet.nac.common.enums.ReprocessState;
import com.fortinet.nac.common.redis.DistributedLock;
import com.fortinet.nac.common.util.StatusOr;
import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.ingestion.job.event.PolicyReprocessRequestedEvent;
import com.fortinet.nac.ingestion.repository.projection.EntityProcessLockInfo;
import com.fortinet.nac.ingestion.service.EntityService;
import com.fortinet.nac.ingestion.util.RedisUtil;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.event.EventListener;
import org.springframework.scheduling.annotation.Async;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import javax.annotation.Resource;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.Executor;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

@Component
@RequiredArgsConstructor
@Slf4j
public class PolicyReprocessJob {

    private final EntityService entityService;
    private final DistributedLock distributedLock;
    private final EntityStateMachine stateMachine;
    private final MeterRegistry meterRegistry;
    private final AtomicInteger scanLockConsecutiveFailures = new AtomicInteger(0);
    @Resource(name = "policyReprocessJobExecutor")
    private Executor policyReprocessJobExecutor;

    @Value("${policy.reprocess.scan-batch-size:${policy.reprocess.batch-size:100}}")
    private int scanBatchSize;

    @Value("${policy.reprocess.max-candidates-per-scan:${policy.reprocess.max-entities-per-scan:1000}}")
    private int maxCandidatesPerScan;

    @Value("${policy.reprocess.rate-limit-per-second:100}")
    private int rateLimitPerSecond;

    @Value("${policy.reprocess.scan-lock-ttl-seconds:900}")
    private int scanLockTtlSeconds;

    @PostConstruct
    public void initMetrics() {
        // Gauge for starvation visibility: how many scan-lock failures occurred continuously.
        meterRegistry.gauge("policy_reprocess_scan_lock_consecutive_failures", scanLockConsecutiveFailures);
    }

    @Scheduled(fixedDelayString = "${policy.reprocess.scan-interval-ms:30000}")
    public void scanAndReprocessInitEntities() {
        triggerScan("scheduled");
    }

    @Async("policyReprocessListenerExecutor")
    @EventListener
    public void onPolicyReprocessRequested(PolicyReprocessRequestedEvent event) {
        log.info("PolicyReprocessJob: receive reprocess trigger from {}, markedCount={}",
                event.getTriggerSource(), event.getMarkedCount());
        triggerScan("event");
    }

    private void triggerScan(String triggerSource) {
        // PolicyReprocessJob currently runs on a single node, so distributed contention is limited.
        // Keep the distributed scan lock for future cluster deployments to prevent concurrent full scans.
        // Global scan lock uses fixed TTL to avoid indefinite lock extension when scan thread is stuck.
        boolean acquired = distributedLock.tryLock(
                Constants.RedisKeys.POLICY_REPROCESS_SCAN_LOCK_KEY,
                Math.max(1, scanLockTtlSeconds));
        recordLockAcquire("scan", acquired);
        if (!acquired) {
            scanLockConsecutiveFailures.incrementAndGet();
            log.warn("PolicyReprocessJob: skip {} trigger because global scan lock is held", triggerSource);
            return;
        }
        scanLockConsecutiveFailures.set(0);

        Timer.Sample lockHoldSample = Timer.start(meterRegistry);

        try {
            drainInitEntities();
        } finally {
            distributedLock.unLock(Constants.RedisKeys.POLICY_REPROCESS_SCAN_LOCK_KEY);
            lockHoldSample.stop(lockHoldTimer("scan"));
        }
    }

    private void drainInitEntities() {
        int effectiveBatchSize = Math.max(1, scanBatchSize);
        int effectiveMaxCandidatesPerScan = Math.max(1, maxCandidatesPerScan);

        ReprocessRateLimiter rateLimiter = new ReprocessRateLimiter(rateLimitPerSecond, meterRegistry);

        int totalScannedCandidates = 0;
        while (totalScannedCandidates < effectiveMaxCandidatesPerScan) {

            // Respect scan-level protection limit to avoid too much one-shot pressure.
            int queryLimit = Math.min(effectiveBatchSize, effectiveMaxCandidatesPerScan - totalScannedCandidates);

            // Query only ids first to avoid fetching large columns such as processingResult.
            List<Long> batchIds = entityService.findTopNIdsByReprocessState(
                    ReprocessState.INIT, queryLimit);
            if (batchIds.isEmpty()) {
                break;
            }
            totalScannedCandidates += batchIds.size();

            processBatchConcurrently(batchIds, rateLimiter);
            log.info("PolicyReprocessJob: batch processed, size={}", batchIds.size());

            // If we got fewer than one full batch, queue is likely drained for this run.
            if (batchIds.size() < queryLimit) {
                break;
            }
        }
    }

    private void processBatchConcurrently(List<Long> batchIds, ReprocessRateLimiter rateLimiter) {
        List<CompletableFuture<Void>> futures = new ArrayList<>(batchIds.size());
        for (Long entityId : batchIds) {
            futures.add(CompletableFuture.runAsync(
                    () -> reprocessOneEntitySafely(entityId, rateLimiter),
                    policyReprocessJobExecutor
            ));
        }

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();
    }

    private void reprocessOneEntitySafely(Long entityId, ReprocessRateLimiter rateLimiter) {
        try {
            reprocessOneEntity(entityId, rateLimiter);
        } catch (Exception ex) {
            log.error("PolicyReprocessJob: reprocess entity {} failed, err={}",
                    entityId, ex.toString(), ex);
        }
    }

    private void reprocessOneEntity(Long entityId, ReprocessRateLimiter rateLimiter) {
        // First read only lock-related fields to avoid loading large columns too early.
        EntityProcessLockInfo lockInfo = entityService.findProcessLockInfoById(entityId);
        if (lockInfo == null) {
            log.warn("PolicyReprocessJob: entity {} not found", entityId);
            return;
        }

        if (lockInfo.getReprocessState() != ReprocessState.INIT) {
            // State already changed by another flow, skip.
            return;
        }

        // 1) Acquire processLock first to avoid conflict with normal ingestion flow.
        String processLockKey = RedisUtil.getEntityProcessLockKey(
                lockInfo.getType(), lockInfo.getHostId(), lockInfo.getAdapterId(), lockInfo.getUserId());
        boolean locked = distributedLock.tryLock(
                processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
        recordLockAcquire("entity", locked);

        if (!locked) {
            // The entity is being handled by other flow; retry next round.
            log.info("PolicyReprocessJob: skip entity {} because processLock is held", entityId);
            return;
        }

        Timer.Sample lockHoldSample = Timer.start(meterRegistry);
        try {
            // Atomic claim in DB: only one worker can move INIT -> RUNNING.
            // claimInitEntityForReprocess is essentially a claim operation for processing ownership:
            //   it turns "check INIT then set RUNNING" into one atomic step to remove race windows.
            boolean claimed = entityService.claimInitEntityForReprocess(entityId);
            if (!claimed) {
                return;
            }

            // Load full entity only after claim succeeds.
            Entity fresh = entityService.getEntity(entityId);
            if (fresh == null) {
                log.warn("PolicyReprocessJob: entity {} missing after claim", entityId);
                return;
            }

            // 2) Reset business processing state so state machine can replay.
            resetEntityProcessingState(fresh);
            boolean ok = entityService.updateProcessingState(fresh);
            if (!ok) {
                log.error("PolicyReprocessJob: failed to reset processing state, entityId={}", entityId);
                boolean updated = entityService.updateReprocessStateById(entityId, ReprocessState.FAILED);
                if (!updated) {
                    log.warn("PolicyReprocessJob: failed to update FAILED reprocess state, entityId={}", entityId);
                }
                recordReprocessCompletion("failed");
                return;
            }

            // 3) Run state machine with rate limiting to protect downstream.
            rateLimiter.acquire();
            String requestId = generateRequestId();
            StatusOr<Entity> result = stateMachine.start(requestId, true, fresh);

            // 4) Update final reprocessState by state machine result.
            if (result.ok()) {
                Entity finalEntity = result.getValue();
                if (EntityStage.ENFORCED.toString().equals(finalEntity.getProcessingStage()) &&
                        finalEntity.getProcessingCode() == 0) {
                    finalEntity.setReprocessState(ReprocessState.SUCCESS);
                } else {
                    finalEntity.setReprocessState(ReprocessState.FAILED);
                }

                // Persist the state-machine final snapshot to avoid overriding it with stale "fresh".
                entityService.save(finalEntity);
                if (finalEntity.getReprocessState() == ReprocessState.SUCCESS) {
                    recordReprocessCompletion("success");
                } else {
                    recordReprocessCompletion("failed");
                }
            } else {
                // State-machine returned error; update FAILED by id to avoid another full-row read.
                boolean updated = entityService.updateReprocessStateById(entityId, ReprocessState.FAILED);
                if (!updated) {
                    log.warn("PolicyReprocessJob: failed to update FAILED state after state machine error, entityId={}", entityId);
                }
                recordReprocessCompletion("failed");
            }

        } finally {
            distributedLock.unLock(processLockKey);
            lockHoldSample.stop(lockHoldTimer("entity"));
        }
    }

    // update in memory
    private void resetEntityProcessingState(Entity e) {
        e.setInterrupted(false);
        e.setProcessingStage(EntityStage.PENDING.toString());
        e.setProcessingCode(0);
        e.setProcessingResult("{}");
        e.setErrorMessage("");
        // Keep lastReqVersion unchanged.
    }

    private String generateRequestId() {
        return UUID.randomUUID().toString().replace("-", "").substring(0, 16);
    }

    private void recordLockAcquire(String lockName, boolean success) {
        meterRegistry.counter(
                "policy_reproc_lock_acquire_total",
                "lock", lockName,
                "result", success ? "success" : "failed"
        ).increment();
    }

    private void recordReprocessCompletion(String result) {
        meterRegistry.counter(
                "policy_reprocess_entity_completed_total",
                "result", result
        ).increment();
    }

    private Timer lockHoldTimer(String lockName) {
        return Timer.builder("policy_reproc_lock_hold_seconds")
                .tag("lock", lockName)
                .register(meterRegistry);
    }

    // ReprocessRateLimiter is a per-second limiter used to protect downstream systems.
    // It prevents PolicyReprocessJob from reprocessing too many entities in a short time.
    private static final class ReprocessRateLimiter {
        private static final long ONE_SECOND_NANOS = TimeUnit.SECONDS.toNanos(1);

        // Token bucket refill rate: number of tokens added per second.
        private final int refillTokensPerSecond;
        // Bucket capacity: allows short bursts while keeping an upper bound.
        private final double capacity;
        // Count how many acquire() calls were throttled (had to wait).
        private final Counter waitCounter;

        private double availableTokens;
        private long lastRefillNanos = System.nanoTime();

        private ReprocessRateLimiter(int maxPerSecond, MeterRegistry meterRegistry) {
            this.refillTokensPerSecond = Math.max(0, maxPerSecond);
            this.capacity = this.refillTokensPerSecond <= 0 ? 0.0 : this.refillTokensPerSecond;
            this.availableTokens = this.capacity;
            this.waitCounter = meterRegistry.counter("policy_reprocess_rate_limiter_wait_total");
        }

        // Call acquire() before each processing attempt, right before stateMachine.start(...).
        private synchronized void acquire() {
            if (refillTokensPerSecond <= 0) {
                return;
            }

            refillTokens();

            if (availableTokens < 1.0) {
                long waitNanos = nanosUntilNextToken();
                if (waitNanos > 0) {
                    waitCounter.increment();
                    try {
                        TimeUnit.NANOSECONDS.sleep(waitNanos);
                    } catch (InterruptedException ex) {
                        Thread.currentThread().interrupt();
                        return;
                    }
                }
                refillTokens();
            }

            // If availableTokens >= 1, consume one token and proceed immediately.
            if (availableTokens >= 1.0) {
                availableTokens -= 1.0;
            } else {
                // Floating-point safety fallback.
                availableTokens = 0.0;
            }
        }

        // Refill tokens based on elapsed time.
        private void refillTokens() {
            long now = System.nanoTime();
            long elapsedNanos = now - lastRefillNanos;
            if (elapsedNanos <= 0) {
                return;
            }

            // Cap refill amount so available tokens never exceed capacity.
            double tokensToAdd = (elapsedNanos / (double) ONE_SECOND_NANOS) * refillTokensPerSecond;
            if (tokensToAdd <= 0.0) {
                return;
            }

            availableTokens = Math.min(capacity, availableTokens + tokensToAdd);
            lastRefillNanos = now;
        }

        // Sleep until at least one token is available.
        private long nanosUntilNextToken() {
            double missingTokens = 1.0 - availableTokens;
            if (missingTokens <= 0.0 || refillTokensPerSecond <= 0) {
                return 0L;
            }

            return (long) Math.ceil((missingTokens / refillTokensPerSecond) * ONE_SECOND_NANOS);
        }
    }
}

